import React from "react";
import "./Sidebar.css";

const Sidebar = ({ 
  isOpen, 
  setIsOpen, 
  view, 
  setView, 
  peers,
  activeTransfers
}) => {
  return (
    <aside className={`sidebar ${isOpen ? "open" : ""}`}>
      <div className="sidebar-section">
        <h3 className="sidebar-title">MAIN NAVIGATION</h3>

        <button
          className={`sidebar-link ${view === "dashboard" ? "active" : ""}`}
          onClick={() => { setView("dashboard"); setIsOpen(false); }}
        >
          <span className="sidebar-icon">📊</span>
          <span className="sidebar-label">Dashboard</span>
        </button>

        <button
          className={`sidebar-link ${view === "peers" ? "active" : ""}`}
          onClick={() => { setView("peers"); setIsOpen(false); }}
        >
          <span className="sidebar-icon">💻</span>
          <span className="sidebar-label">Peers</span>
          <span className="count-badge">{peers?.length || 0}</span>
        </button>

        <button
          className={`sidebar-link ${view === "upload" ? "active" : ""}`}
          onClick={() => { setView("upload"); setIsOpen(false); }}
        >
          <span className="sidebar-icon">📤</span>
          <span className="sidebar-label">Upload to Peer</span>
        </button>

        <button
          className={`sidebar-link ${view === "transfers" ? "active" : ""}`}
          onClick={() => { setView("transfers"); setIsOpen(false); }}
        >
          <span className="sidebar-icon">🔄</span>
          <span className="sidebar-label">Transfers</span>
          {activeTransfers > 0 && <span className="count-badge">{activeTransfers}</span>}
        </button>

        <button
          className={`sidebar-link ${view === "files" ? "active" : ""}`}
          onClick={() => { setView("files"); setIsOpen(false); }}
        >
          <span className="sidebar-icon">📁</span>
          <span className="sidebar-label">Received Files</span>
        </button>
      </div>
    </aside>
  );
};

export default Sidebar;
